```java
import java.util.Arrays;

class Solution {
    /**
     * @param nums Array of strictly increasing integers.
     * @param queries Array of [l_i, r_i] pairs.
     * @return Array of minimum total costs.
     */
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;

        // 1. Precompute closest(x) for all x
        int[] closest = new int[n];
        for (int x = 0; x < n; x++) {
            long minDiff = Long.MAX_VALUE;
            int bestY = -1;

            // Check adjacent neighbors y = x-1 and y = x+1
            // Since nums is strictly increasing, the neighbor difference is guaranteed to be non-zero.

            // Candidates are x-1 and x+1
            int[] neighbors = new int[2];
            int count = 0;
            if (x > 0) {
                neighbors[count++] = x - 1;
            }
            if (x < n - 1) {
                neighbors[count++] = x + 1;
            }

            for (int i = 0; i < count; i++) {
                int y = neighbors[i];
                long diff = Math.abs(nums[x] - nums[y]);

                if (diff < minDiff) {
                    minDiff = diff;
                    bestY = y;
                } else if (diff == minDiff) {
                    // If differences are equal, choose the smaller index
                    if (y < bestY) {
                        bestY = y;
                    }
                }
            }
            closest[x] = bestY;
        }

        long[] results = new long[queries.length];

        for (int i = 0; i < queries.length; i++) {
            int l = (int) queries[i][0];
            int r = (int) queries[i][1];

            if (l == r) {
                results[i] = 0;
                continue;
            }

            // Initial minimum cost: Direct jump (Type 1 move from l to r)
            long minCost = Math.abs(nums[l] - nums[r]);

            // Explore paths starting from l using only type 2 moves (l -> k) followed by a final move (k -> r)
            // This traversal finds min_{k in Reachable(l)} { dist_2(l, k) + Cost(k -> r) }

            int current = l;
            int dist2_l_k = 0;
            boolean[] visited = new boolean[n];

            while (true) {
                if (visited[current]) {
                    // Cycle detected or loop closed. Stop traversing the chain.
                    break;
                }
                visited[current] = true;

                // --- Check transition current -> r ---

                // Option A: Type 1 Jump from current to r
                // Cost = dist2_l_k + |nums[current] - nums[r]|
                long costViaCurrentJump = (long)dist2_l_k + Math.abs(nums[current] - nums[r]);
                minCost = Math.min(minCost, costViaCurrentJump);

                // Option B: Type 2 Move from current to r, if r == closest(current)
                if (r == closest[current]) {
                    // Cost = dist2_l_k + 1
                    minCost = Math.min(minCost, (long)dist2_l_k + 1);
                }

                // Move to the next node in the closest chain (Type 2 move)
                int next = closest[current];

                // Since the graph is functional (out-degree 1), we must continue following the chain unless we hit a visited node.

                current = next;
                dist2_l_k++;
            }

            results[i] = minCost;
        }

        return results;
    }
}
