            List<Integer> neighbors = new ArrayList<>();
            if (x > 0) neighbors.add(x - 1);
            if (x < n - 1) neighbors.add(x + 1);

            for (int y : neighbors) {
                long diff = Math.abs(nums[x] - nums[y]);

                if (diff < minDiff) {
