                    if (y < bestY) {
                        bestY = y;
                    }
                }
            }
            closest[x] = bestY;
        }

        long[] ans = new long[queries.length];

        for (int i = 0; i < queries.length; i++) {
            int l = (int) queries[i][0];
            int r = (int) queries[i][1];

            if (l == r) {
                ans[i] = 0;
                continue;
